import React from "react";
import { ReactComponent as PhotoAutomatSVG } from "../public/photoautomat.svg"; 

const Home = () => {
  return (
    <div className="background-gradient h-screen flex flex-col justify-center items-center text-center">
      <div className="home-container">
        <h1 className="text-5xl font-bold text-pink-600 mb-4 font-Phudu">
          Capturing | Booth
        </h1>

        <h4 className="text-lg text-gray-700 mb-6">
          Welcome to Capturing! Photobooth! Lumen & LifeVoyage.
        </h4>

        {/* ✅ ใส่คลาสที่ SVG */}
        <PhotoAutomatSVG className="photoautomat-svg" />

        <button onClick={() => navigate("/welcome")} className="start-button">
          START
        </button>

        <footer className="mt-8 text-sm text-gray-600 text-center font-kanit">
          <p>Version 1.0.3</p>
        </footer>
      </div>
    </div>
  );
};

export default Home;
